from collections import Counter

def solve(histories: list[list[dict]]) -> str:
    if not histories:
        return "intern"

    all_actions = []
    for history in histories:
        actions = [entry.get("action", "read") for entry in history]
        all_actions.extend(actions)

    action_counts = Counter(all_actions)
    top_action = action_counts.most_common(1)[0][0]

    mapping = {
        "read": "intern",
        "write": "director",
        "delete": "engineer",
        "admin": "manager",
    }

    return mapping.get(top_action, "director")
