def solve(series_list: List[str], factor: float) -> float:
    def parse_series(series_str: str) -> Dict[str, Any]:
        # Assuming the series string format is "timestamp:value"
        timestamps = []
        values = []
        for item in series_str.split(';'):
            ts, val = item.split(':')
            timestamps.append(int(ts))
            values.append(float(val))
        return {"timestamps": timestamps, "values": values}

    def scale_series(series: Dict[str, Any], factor: float) -> Dict[str, Any]:
        return {
            "timestamps": series["timestamps"],
            "values": [value * factor for value in series["values"]]
        }

    def merge_series(series_list: List[Dict[str, Any]]) -> Dict[str, Any]:
        merged = {}
        for series in series_list:
            for ts, value in zip(series["timestamps"], series["values"]):
                if ts in merged:
                    merged[ts] += value
                else:
                    merged[ts] = value
        sorted_ts = sorted(merged)
        return {"timestamps": sorted_ts, "values": [merged[ts] for ts in sorted_ts]}

    def forecast_next_value(series: Dict[str, Any], method: str = "mean") -> float:
        if method == "mean":
            return sum(series["values"]) / len(series["values"])
        elif method == "median":
            sorted_values = sorted(series["values"])
            n = len(sorted_values)
            if n % 2 == 1:
                return sorted_values[n // 2]
            else:
                return (sorted_values[n // 2 - 1] + sorted_values[n // 2]) / 2
        else:
            raise ValueError("Unsupported forecasting method")

    parsed_series = [parse_series(series) for series in series_list]
    scaled_series = [scale_series(series, factor) for series in parsed_series]
    merged_series = merge_series(scaled_series)
    return forecast_next_value(merged_series, method="mean")
